# Compute LCS ratio and token F1 quickly
def lcs(a, b):
    # dynamic programming LCS length
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1]==b[j-1]:
                dp[j] = prev + 1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = tmp
    return dp[m]

def lcs_ratio(a,b):
    L = lcs(a,b)
    return L / max(1, max(len(a),len(b)))

def token_f1(a,b):
    ta = a.split()
    tb = b.split()
    ca = Counter(ta)
    cb = Counter(tb)
    inter = sum((ca & cb).values())
    prec = inter / max(1, sum(ca.values()))
    rec = inter / max(1, sum(cb.values()))
    if prec+rec==0: 
        f1= 0.0
    else:
        f1 = 2*prec*rec/(prec+rec)
    return f1, prec, rec, inter, len(ta), len(tb)

